        xs, ys = series_at(pl)
        den = (xs - xP) * (xs - xQ)
        sers = [xs**aa * ys**bb / den for (aa, bb) in POOL]
        sers_at[pl] = (xs, ys, sers)
        minv = min(t.valuation() for t in sers)
        for order in range(minv, -a):
            rows.append([t[order] for t in sers])
