def add_pts(P1, P2):
    """Group law on y^2 + 2xy + y = x^3 (a1=2, a3=1)."""
    x1, y1 = P1
    x2, y2 = P2
    if x1 == x2 and (y1 + y2 + _sage_const_2 *x1 + _sage_const_1 ) == _sage_const_0 :
        return 'O'
    if P1 == P2:
        lam = (_sage_const_3 *x1**_sage_const_2  - _sage_const_2 *y1) / (_sage_const_2 *y1 + _sage_const_2 *x1 + _sage_const_1 )
    else:
        lam = (y2 - y1) / (x2 - x1)
    x3 = lam**_sage_const_2  + _sage_const_2 *lam - x1 - x2
    y3 = lam*(x1 - x3) - y1 - _sage_const_2 *x3 - _sage_const_1 
    return (x3, y3)


